SELECT MAP(ARRAY['Mobile Home', 'Single-Family Detached', 'Single-Family Attached', 'Multi-Family with 2 - 4 Units', 'Multi-Family with 5+ Units'], ARRAY['MH', 'SF', 'SF', 'MF', 'MF'])[bs."in.geometry_building_type_recs"] AS simple_bldg_type, sum(1) AS sample_count, sum(bs.weight) AS units_count, sum(bs."out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption" FROM resstock_2024_amy2018_release_2_metadata AS bs WHERE bs.applicability = true AND bs.upgrade = 0 AND bs."in.state" = 'CO' GROUP BY 1 ORDER BY 1